def load_day_idempotent(conn, date, rows):
    with conn.begin():  # single transaction = atomic
        conn.execute(
            "DELETE FROM events WHERE event_date = %s", (date,)
        )
        conn.executemany(
            "INSERT INTO events (event_date, user_id, payload) "
            "VALUES (%s, %s, %s)",
            [(date, r["user_id"], r["payload"]) for r in rows],
        )

import hashlib

def event_id(user_id, event_type, occurred_at):
    raw = f"{user_id}|{event_type}|{occurred_at.isoformat()}"
    return hashlib.sha256(raw.encode()).hexdigest()

# ❌ NOT idempotent — appends every time, creates duplicates on retry
def load_bad(conn, rows):
    conn.executemany(
        "INSERT INTO sales (id, amount) VALUES (%s, %s)",
        [(r["id"], r["amount"]) for r in rows],
    )

# ✅ Idempotent — upsert keyed on id, same result no matter how often it runs
def load_good(conn, rows):
    conn.executemany(
        "INSERT INTO sales (id, amount) VALUES (%s, %s) "
        "ON CONFLICT (id) DO UPDATE SET amount = EXCLUDED.amount",
        [(r["id"], r["amount"]) for r in rows],
    )

import json, pathlib

def process_new_files(folder, sink, state_path="processed.json"):
    seen = set(json.loads(pathlib.Path(state_path).read_text())) \
        if pathlib.Path(state_path).exists() else set()

    for f in sorted(pathlib.Path(folder).glob("*.csv")):
        if f.name in seen:
            continue                    # incremental: skip done files
        sink.load_csv(f)
        seen.add(f.name)
        pathlib.Path(state_path).write_text(json.dumps(sorted(seen)))
